+{
+    char *copy;
+    int ok;
+
+    if (!asx_codec_slice_nonempty(slice) || asx_codec_slice_contains_nul(slice)) {
+        return 0;
+    }
+
+    copy = asx_codec_strdup_range(slice.ptr, slice.len);
+    if (copy == NULL) {
+        return 0;
+    }
+
+    ok = asx_codec_json_value_matches(copy, expected_first_char);
+    free(copy);
+    return ok;
